+fn split_yaml_frontmatter(body: &str) -> Option<(&str, &str)> {
+    let normalized = body.replace("\r\n", "\n").replace('\r', "\n");
+    if !normalized.starts_with("---\n") {
+        return None;
+    }
+
+    let closing_offset = normalized[4..].find("\n---\n")?;
+    let frontmatter_end = 4 + closing_offset + "\n---\n".len();
+
+    if frontmatter_end > body.len() {
+        return None;
+    }
+
+    Some((&body[..frontmatter_end], &body[frontmatter_end..]))
 }
